package domain

import "testing"

func TestSlugFromPath(t *testing.T) {
	tests := []struct {
		input string
		want  string
	}{
		{"docs/fpf-spec.md", "fpf-spec"},
		{"docs/architecture.md", "architecture"},
		{"fpf-spec.md", "fpf-spec"},
		{"My Document.md", "my-document"},
		{"UPPER_CASE.txt", "upper-case"},
		{".hidden.md", "hidden"},
		{"docs/some path/doc.md", "doc"},
		{"no-extension", "no-extension"},
		{"decision-009-embedding.md", "decision-009-embedding"},
		{"docs/My Cool Doc!!!.md", "my-cool-doc"},
	}

	for _, tt := range tests {
		t.Run(tt.input, func(t *testing.T) {
			got := SlugFromPath(tt.input)
			if got != tt.want {
				t.Errorf("SlugFromPath(%q) = %q, want %q", tt.input, got, tt.want)
			}
		})
	}
}

func TestQualifiedID(t *testing.T) {
	tests := []struct {
		slug      string
		sectionID string
		want      string
	}{
		{"fpf-spec", "A.1", "fpf-spec:A.1"},
		{"architecture", "overview", "architecture:overview"},
		{"doc", "3", "doc:3"},
	}

	for _, tt := range tests {
		t.Run(tt.want, func(t *testing.T) {
			got := QualifiedID(tt.slug, tt.sectionID)
			if got != tt.want {
				t.Errorf("QualifiedID(%q, %q) = %q, want %q", tt.slug, tt.sectionID, got, tt.want)
			}
		})
	}
}
